async (params, browser) => {
  // Open Gmail inbox
  await browser.open('https://mail.google.com/mail/u/0/#inbox')

  // Wait for inbox to load
  await browser.waitForSelector('tr.zA, [data-message-id], .yO', 15000)

  // Let inbox fully render
  await browser.wait(2000)

  // Scrape inbox messages
  const inbox_messages = await browser.evaluate(`const count = parseInt(params.count) || 10; const rows = document.querySelectorAll('tr.zA'); const messages = []; for (let i = 0; i < Math.min(rows.length, count); i++) { const row = rows[i]; const senderEl = row.querySelector('.yX .yW span[email], .zF'); const subjectEl = row.querySelector('.bog span, .y6 span'); const previewEl = row.querySelector('.y2'); const dateEl = row.querySelector('.xW span[title], .xW span'); const isUnread = row.classList.contains('zE'); const starEl = row.querySelector('.T-KT'); const isStarred = starEl ? starEl.classList.contains('T-KT-Jp') : false; messages.push({ sender: senderEl ? (senderEl.getAttribute('email') || senderEl.getAttribute('name') || senderEl.textContent.trim()) : '', subject: subjectEl ? subjectEl.textContent.trim() : '', preview: previewEl ? previewEl.textContent.trim().replace(/^\s*-\s*/, '') : '', date: dateEl ? (dateEl.getAttribute('title') || dateEl.textContent.trim()) : '', unread: isUnread, starred: isStarred }); } return { inbox_count: messages.length, messages: messages }`)

  return inbox_messages
}
